using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace MyApp.Tests;

public class CategorizedTestMethodAttribute : TestMethodAttribute
{
    public string Category { get; }

    public CategorizedTestMethodAttribute(
        string category,
        [CallerFilePath] string callerFilePath = "",
        [CallerLineNumber] int callerLineNumber = -1)
        : base(callerFilePath, callerLineNumber)
    {
        Category = category;
    }
}

[TestClass]
public class ServiceTests
{
    [CategorizedTestMethod("Integration")]
    public void ConnectToDatabase_Succeeds()
    {
        Assert.IsTrue(true);
    }

    [TestMethod(DisplayName = "My custom display name")]
    public void SimpleTest()
    {
        Assert.IsTrue(true);
    }
}

